select resources_ip from server_resources where  resources_ip = #{ip} and is_deleted = 0
union
select resources_ip from resource_allocation_temporary_storage where  resources_ip = #{ip}

select sr.id as resourcesId, sr.resources_ip resourcesIp, sr.commodity_id as commodityId, c.commodity_name as commodityName, c.category_id as commodityCategoryId, cc.category_name as commodityCategoryName, vi.vendor_name as vendorName, sr.resources_status, sr.sales_status, sr.available_status, sr.vendor_account_id from server_resources sr left join commodity c on sr.commodity_id = c.id left join commodity_category cc on c.category_id = cc.id left join vendor_account_information vai on sr.vendor_account_id = vai.id left join vendor_information vi on vai.vendor_id = vi.id where 1=1 and sr.is_deleted = 0
and sr.resources_ip like concat('%',#{dto.resourcesIp},'%')
and sr.resources_status = #{dto.resourcesStatus}
and sr.sales_status = #{dto.salesStatus}
and sr.available_status = #{dto.availableStatus}
and vai.vendor_id = #{dto.vendorId}
and vai.id = #{dto.vendorAccountId}
and sr.commodity_id = #{dto.commodityId}
and c.category_id = #{dto.commodityCategoryId}

select sr.id as resourcesId, sr.resources_ip resourcesIp, sr.commodity_id as commodityId, c.commodity_name as commodityName, c.category_id as commodityCategoryId, cc.category_name as commodityCategoryName, sr.resources_status, sr.sales_status, sr.available_status, srr.renewal_switch as renewalSwitch, srr.renewal_period as renewalPeriod, sr.lease_expiration_time as leaseExpirationTime, c.bandwidth, c.description from server_resources sr left join commodity c on sr.commodity_id = c.id left join commodity_category cc on c.category_id = cc.id left join server_resources_renewal srr on sr.id = srr.resources_id and srr.is_deleted = 0 and srr.user_id = #{userId} where 1=1 and sr.is_deleted = 0 and sr.sales_status = 'SALE' and sr.lease_expiration_time > now() and resource_tenant=#{userId}
and sr.lease_expiration_time <= #{time}
and sr.resources_ip like concat('%',#{dto.resourcesIp},'%')
and sr.resources_status = #{dto.resourcesStatus}
and sr.commodity_id = #{dto.commodityId}
and c.category_id = #{dto.commodityCategoryId}
and srr.renewal_switch = #{dto.isOpenRenewal}
